data.content:
**MSTest does not have `Assert.IsGreaterThan` or `Assert.IsInRange`** — those don't exist. Here's what to use instead:

| Need | MSTest Approach |
|------|----------------|
| Exact value | `Assert.AreEqual(expected, actual, delta)` |
| Comparison | `Assert.IsTrue(value >= 0, "message")` |
| Range check | `Assert.IsTrue(value >= lo && value <= hi)` |
| Exceptions | `Assert.ThrowsException<T>(() => ...)` |

For double comparisons, `Assert.AreEqual` accepts a `delta` tolerance parameter (3rd arg).

Example tests for your class:

```csharp
using Microsoft.VisualStudio.TestTools.UnitTesting;
using Contoso.Scoring;

namespace Contoso.Scoring.Tests;

[TestClass]
public class ScoreCalculatorTests
{
    private readonly ScoreCalculator _calc = new();

    [TestMethod]
    public void CalculatePercentage_PerfectScore_Returns100()
    {
        Assert.AreEqual(100.0, _calc.CalculatePercentage(10, 10), 0.001);
    }

    [TestMethod]
    public void CalculatePercentage_ResultIsInValidRange()
    {
        double result = _calc.CalculatePercentage(7, 10);
        Assert.IsTrue(result >= 0.0 && result <= 100.0,
            $"Expected 0–100 but got {result}");
    }

    [TestMethod]
    public void CalculatePercentage_ZeroTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(5, 0));
    }

    [TestMethod]
    public void CalculatePercentage_NegativeCorrect_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(-1, 10));
    }

    [TestMethod]
    public void CalculatePercentage_CorrectExceedsTotal_Throws()
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calc.CalculatePercentage(11, 10));
    }

    [DataTestMethod]
    [DataRow(90.0, "A")]
    [DataRow(89.9, "B")]
    [DataRow(80.0, "B")]
    [DataRow(70.0, "C")]
    [DataRow(60.0, "D")]
    [DataRow(59.9, "F")]
    public void GetGrade_BoundaryValues(double pct, string expected)
    {
        Assert.AreEqual(expected, _calc.GetGrade(pct));
    }

    [TestMethod]
    public void NormalizeScore_NeverExceeds100()
    {
        double result = _calc.NormalizeScore(150, 100);
        Assert.IsTrue(result <= 100.0,
            $"Expected at most 100 but got {result}");
    }

    [TestMethod]
    public void NormalizeScore_HalfRaw_Returns50()
    {
        Assert.AreEqual(50.0, _calc.NormalizeScore(25, 50), 0.001);
    }
}
```

**Key takeaways:**
- Use `Assert.AreEqual(expected, actual, delta)` for floating-point equality
- Use `Assert.IsTrue(...)` with a descriptive message for range/comparison checks
- Use `Assert.ThrowsException<T>` for boundary violation exceptions
- Use `[DataTestMethod]`/`[DataRow]` to test multiple boundary values concisely
